css:
/* 引入字体 */
@import url('https://fonts.font.im/css2?family=Inter:wght@400;500;700&display=swap');
@import url('https://fonts.font.im/css2?family=Noto+Sans+SC:wght@400;500&display=swap');
@import url('https://fonts.loli.net/css2?family=Inter:wght@400;500;700&display=swap');
@import url('https://fonts.loli.net/css2?family=Noto+Sans+SC:wght@400;500&display=swap');

/* 通用字体设置 */
body, html {
    font-family: 'Inter', sans-serif; /* 英文部分使用 Inter 字体 */
    line-height: 1.8; /* 增强行间距，提升阅读舒适度 */
    color: rgba(240, 240, 240, 1); /* 使用 main_text_color 作为文本颜色 */
    font-size: 1.02em; /* 增大字体大小，适合长时间阅读 */
}

/* 中文字体设置 */
p, q, h1, h2, h3, h4, h5, h6, i, strong, #send_textarea, .font-box, .formatted-text, * {
    font-family: 'Noto Sans SC', sans-serif; /* 中文部分使用 Noto Sans SC */
}

/* 小代码块样式 */
code, .custom-json, .custom-yaml, .hljs {
    font-family: 'Courier New', monospace; /* 使用标准等宽字体 */
    padding: 6px 12px;
    line-height: 1.6;
    border-radius: 8px;
    border: 1px solid rgba(255, 255, 255, 0.15); /* 设置淡白色的边框 */
    color: rgba(240, 240, 240, 1); /* 使用 main_text_color */
    background: rgba(30, 30, 35, 0.15); /* 背景透明度为15% */
    overflow-x: auto;
    text-shadow: 0 1px 3px rgba(255, 255, 255, 0.3); /* 设置发光效果 */
}

/* 段落文本 */
p {
    color: rgba(240, 240, 240, 1); /* 使用 main_text_color */
    font-size: 1.02em; /* 增加字体大小 */
    line-height: 1.8; /* 增加行间距 */
}

/* 引号文本 */
q {
    color: rgba(230, 170, 100, 1); /* 使用 quote_text_color */
    font-size: 1.02em; /* 增加引用文本的字体大小 */
}

/* 列表项 */
li {
    color: rgba(240, 240, 240, 1); /* 使用 main_text_color */
    margin-bottom: 5px;
    font-size: 1.02em; /* 增加字体大小 */
}

/* 标题 */
h1, h2, h3, h4, h5, h6 {
    color: rgba(240, 240, 240, 1); /* 使用 main_text_color */
    margin-bottom: 15px;
    font-weight: 700; /* 加大标题字体的加粗效果 */
}

/* 加粗文本 */
strong {
    color: rgba(240, 240, 240, 1); /* 使用 main_text_color */
    font-weight: 700; /* 增加加粗的效果 */
}

/* 斜体文本 */
i {
    color: rgba(160, 160, 160, 1); /* 使用 italics_text_color */
}

/* 输入框 */
#send_textarea {
    color: rgba(240, 240, 240, 1); /* 使用 main_text_color */
    background-color: rgba(35, 35, 40, 0.15); /* 设置背景透明度为15% */
    border: 1px solid rgba(255, 255, 255, 0.15); /* 设置淡白色的边框 */
    border-radius: 6px;
    padding: 12px;
    resize: none;
    font-size: 0.6em; /* 增加输入框字体大小 */
}

/* 消息气泡样式 */
body.bubblechat .mes_block {
    background-color: rgba(40, 40, 45, 0.15); /* 背景透明度为15% */
    border-radius: 12px;
    box-shadow: 0 4px 8px rgba(255, 255, 255, 0.3); /* 设置发光的阴影 */
    color: rgba(240, 240, 240, 1); /* 使用 main_text_color */
    padding: 12px;
    margin: 6px 0;
    border: 1px solid rgba(255, 255, 255, 0.15); /* 设置淡白色的边框 */
}

body.bubblechat .mes[is_user="true"] .mes_block {
    background-color: rgba(38, 38, 43, 0.15); /* 背景透明度为15% */
    color: rgba(240, 240, 240, 1); /* 使用 main_text_color */
    border: 1px solid rgba(255, 255, 255, 0.15); /* 设置淡白色的边框 */
    box-shadow: 0 4px 8px rgba(255, 255, 255, 0.3); /* 设置发光的阴影 */
}

/* 按钮样式 */
.menu_button, text_pole, textarea {
    background-color: rgba(35, 35, 40, 0.15); /* 背景透明度为15% */
    color: rgba(240, 240, 240, 1); /* 使用 main_text_color */
    border: 1px solid rgba(255, 255, 255, 0.15); /* 设置淡白色的边框 */
    border-radius: 8px;
    padding: 12px 18px;
    cursor: pointer;
    transition: all 0.3s ease;
    font-size: 0.8em; /* 增加按钮字体大小 */
}

.text_pole, textarea {
    font-size: 0.9em;
}

.menu_button:hover, .text_pole:hover, textarea:hover {
    background-color: rgba(50, 50, 60, 0.15); /* 稍微加深背景色 */
    border-color: rgba(255, 255, 255, 0.25); /* 增强边框颜色 */
}

* {
    scrollbar-color: rgba(255, 255, 255, 0.25) rgba(30, 30, 36, 0); /* 使用淡白色滚动条和透明背景 */
    scrollbar-width: thin;
}

::-webkit-scrollbar {
    width: 4px;
    height: 4px;
}

::-webkit-scrollbar-thumb {
    background-color: rgba(255, 255, 255, 0.25); /* 使用淡白色的边框 */
    border-radius: 6px;
}

::-webkit-scrollbar-thumb:hover {
    background-color: rgba(255, 255, 255, 0.25);
}

::-webkit-scrollbar-track {
    background-color: rgba(0, 0, 0, 0); /* 使用 chat_tint_color */
}

/* 设置响应式设计 */
@media (max-width: 768px) {
    .mes_block, .menu_button, .text_pole, #send_textarea {
        padding: 8px 12px;
        font-size: 14px;
    }
}

/* 容器部分设置 */
.mes, .last_mes {
    display: flex;
    flex-direction: column;
    margin-bottom: 20px; /* 增加消息的间距 */
}

/* 头像容器设置 */
.mesAvatarWrapper, .last_mes .mesAvatarWrapper {
    display: flex;
    align-items: center;
    margin-bottom: 10px; /* 增加头像与其他内容的间距 */
    padding: 0;
}

/* 头像 */
.mesAvatarWrapper .avatar, .last_mes .mesAvatarWrapper .avatar {
    width: 50px;
    height: 50px;
    border-radius: 50%;
    margin-right: 15px; /* 增加头像与文本的间距 */
}

.mesAvatarWrapper .avatar img, .last_mes .mesAvatarWrapper .avatar img {
    width: 100%;
    height: 100%;
    border-radius: 50%;
}

/* 显示消息的用户名、时间和ID */
.mesAvatarWrapper .mesIDDisplay,
.mesAvatarWrapper .mes_timer,
.mesAvatarWrapper .tokenCounterDisplay,
.last_mes .mesAvatarWrapper .mesIDDisplay,
.last_mes .mesAvatarWrapper .mes_timer,
.last_mes .mesAvatarWrapper .tokenCounterDisplay {
    margin-left: 5px;
}

/* 主体消息区域 */
.mes_block, .last_mes .mes_block {
    background-color: rgba(35, 35, 40, 0.15); /* 背景透明度为15% */
    border-radius: 10px;
    padding: 20px;
    margin-top: 10px;
    border: 1px solid rgba(255, 255, 255, 0.15); /* 设置淡白色的边框 */
    backdrop-filter: blur(5px); /* 设置毛玻璃效果 */
}

/* 消息的用户名字、时间显示 */
.mes_block .ch_name, .last_mes .mes_block .ch_name {
    display: flex;
    justify-content: space-between;
    margin-bottom: 10px;
    align-items: center;
}

/* 用户名区域 */
.mes_block .ch_name .name_text, .last_mes .mes_block .ch_name .name_text {
    font-weight: 700;
}

/* 消息文本 */
.mes_text q, .last_mes .mes_text q {
    margin-top: 10px; /* 增加引用文本和其他文本的间距 */
}

/* 文字区域 */
.mes_text p, .last_mes .mes_text p {
    margin: 0;
}

/* 消息文本 */
.mes_text, .last_mes .mes_text {
    font-size: 1.0em;
}

.mes_text > p {
    margin-bottom: 12px; /* 添加较小的间距，改善阅读性 */
}

.last_mes .mes_text > p {
    margin-bottom: 12px; /* 添加较小的间距，改善阅读性 */
}

/* 仅对 last_mes 的 mes_text 做调整 */
.last_mes .mes_text {
    width: 100%; /* 确保文本区域占满父容器宽度 */
    padding: 5px 0px; /* 确保左右间距适中 */
    box-sizing: border-box; /* 确保 padding 不影响宽度 */
    backdrop-filter: blur(5px); /* 毛玻璃效果 */
}

.mes_img_controls, .last_mes .mes_img_controls {
    display: flex;
    gap: 10px;
    margin-bottom: 10px;
}

/* 图片内容 */
.mes_img, .last_mes .mes_img {
    max-width: 100%;
    border-radius: 10px;
}

/* 消息底部控制区 */
.mes_bias, .last_mes .mes_bias {
    height: 10px;
    background-color: rgba(40, 40, 45, 0.15);
    border-radius: 8px;
}

/* 消息状态操作区 */
.flex-container.swipeRightBlock, .last_mes .flex-container.swipeRightBlock {
    display: flex;
    justify-content: center;
    margin-top: 10px;
}

/* 设置响应式设计 */
@media (max-width: 768px) {
    .mes_block, .last_mes .mes_block {
        padding: 15px;
    }

    .mes_buttons, .last_mes .mes_buttons {
        flex-direction: column;
        gap: 5px;
    }

    .mes_img_container, .last_mes .mes_img_container {
        margin-top: 10px;
    }

    .mes_text, .last_mes .mes_text {
        font-size: 1.15em;
    }
}
